sub read_log_file {
    my $path = shift;
    my $content = '';
    my @lines = ();
    my $bytes_read = 0;

    open(my $fh, '<:encoding(UTF-8)', $path) or return $q->p("Could not open file '$path': $!");

    # Acquire a shared lock to prevent log rotation issues while reading
    # (though log rotation usually renames the file, this can help with active writes)
    unless (flock($fh, LOCK_SH | LOCK_NB)) { # Non-blocking shared lock
        # Could not acquire lock, proceed anyway or return error
        warn "Could not acquire shared lock on $path: $!";
    }

    # Read from the end of the file
    seek($fh, 0, SEEK_END);
    my $file_size = tell($fh);
    my $bytes_to_read = $file_size > $max_bytes ? $max_bytes : $file_size;

    # Move pointer back by $bytes_to_read
    seek($fh, -$bytes_to_read, SEEK_CUR);

    # Read bytes from the calculated position
    my $buffer;
    read($fh, $buffer, $bytes_to_read);

    # Split into lines and take the last $max_lines
    @lines = split(/\n/, $buffer);

    # The first line might be truncated, so discard it unless we read the entire file
    if ($file_size > $max_bytes && scalar(@lines) > 0) {
        shift @lines;
    }

    # Take the last $max_lines lines
    if (scalar(@lines) > $max_lines) {
        splice(@lines, 0, scalar(@lines) - $max_lines);
    }

    $content = join("\n", @lines);

    # Release the lock
    flock($fh, LOCK_UN) or warn "Could not unlock $path: $!";

    close $fh;
    return $content;
